     1→/**
     2→ * File Search Store API
     3→ * New SDK (@google/genai) based File Search Store implementation
     4→ *
     5→ * Uses fileSearch tool for semantic search across uploaded documents
     6→ */
     7→
     8→import { GoogleGenAI } from '@google/genai';
     9→import { logger } from '@/server/lib/logger';
    10→import { getGenerativeModelId } from '../config';
    11→import type { FileSearchResult } from '@/types/gemini';
    12→import type { Manifest } from './types';
    13→import { buildFileSearchPrompt, extractCategories } from './prompts';
    14→import { parseSearchResults } from './parser';
    15→import { performLegacySearch } from './legacy-search';
    16→
    17→/**
    18→ * Perform search using File Search Store API (new SDK)
    19→ */
    20→export async function performFileSearchStoreSearch(
    21→  apiKey: string,
    22→  query: string,
    23→  numResults: number,
    24→  manifest: Manifest
    25→): Promise<FileSearchResult[]> {
    26→  try {
    27→    logger.info(
    28→      {
    29→        totalFiles: manifest.files.length,
    30→        version: manifest.version,
    31→        fileSearchStoreName: manifest.file_search_store_name,
    32→      },
    33→      '[File Search Store] Manifest loaded'
    34→    );
    35→
    36→    // Fall back to legacy mode if no file_search_store_name
    37→    if (!manifest.file_search_store_name) {
    38→      logger.warn('[File Search Store] No file_search_store_name in manifest, using legacy mode');
    39→      return performLegacySearch(apiKey, query, numResults, manifest);
    40→    }
    41→
    42→    // Create client with new SDK
    43→    const ai = new GoogleGenAI({ apiKey });
    44→
    45→    // Extract available categories
    46→    const availableCategories = extractCategories(manifest.files);
    47→    logger.info({ availableCategories }, '[File Search Store] Available categories');
    48→
    49→    // Build search prompt (shared with legacy search)
    50→    const searchPrompt = buildFileSearchPrompt(query, availableCategories, numResults);
    51→
    52→    logger.info('[File Search Store] Calling Gemini API with fileSearch tool');
    53→
    54→    // generateContent with fileSearch tool (new SDK)
    55→    const response = await ai.models.generateContent({
    56→      model: getGenerativeModelId(),
    57→      contents: searchPrompt,
    58→      config: {
    59→        tools: [
    60→          {
    61→            fileSearch: {
    62→              fileSearchStoreNames: [manifest.file_search_store_name],
    63→            },
    64→          },
    65→        ],
    66→        temperature: 0.1,
    67→      },
    68→    });
    69→
    70→    // Debug: output full response structure
    71→    logger.info(
    72→      {
    73→        responseKeys: Object.keys(response),
    74→        candidates: response.candidates?.length,
    75→        fullResponse: JSON.stringify(response).substring(0, 1000),
    76→      },
    77→      '[File Search Store] Full API response'
    78→    );
    79→
    80→    const text = response.text || '';
    81→
    82→    logger.info(
    83→      {
    84→        textLength: text.length,
    85→        preview: text.substring(0, 200),
    86→      },
    87→      '[File Search Store] Gemini API response'
    88→    );
    89→
    90→    // Log grounding metadata if available
    91→    if (response.candidates?.[0]?.groundingMetadata) {
    92→      logger.info(
    93→        { groundingMetadata: response.candidates[0].groundingMetadata },
    94→        '[File Search Store] Grounding metadata'
    95→      );
    96→    }
    97→
    98→    // Parse response
    99→    const results = parseSearchResults(text, manifest);
   100→    logger.info(
   101→      {
   102→        count: results.length,
   103→        results: results.map(r => ({
   104→          question: r.original_question?.substring(0, 50),
   105→          type: r.source_type,
   106→        })),
   107→      },
   108→      '[File Search Store] Parsed results'
   109→    );
   110→
   111→    return results.slice(0, numResults);
   112→  } catch (error) {
   113→    logger.error({ error }, '[File Search Store] Search error');
   114→    // Fall back to legacy mode on error
   115→    return performLegacySearch(apiKey, query, numResults, manifest);
   116→  }
   117→}
