     1→/**
     2→ * Search Results Parser
     3→ * Parses Gemini API response into structured FileSearchResult
     4→ */
     5→
     6→import { logger } from '@/server/lib/logger';
     7→import type { FileSearchResult } from '@/types/gemini';
     8→import type { Manifest, ManifestFile, ParsedSearchResult } from './types';
     9→
    10→/**
    11→ * Parse search results from Gemini response text
    12→ */
    13→export function parseSearchResults(responseText: string, manifest: Manifest): FileSearchResult[] {
    14→  try {
    15→    // Remove markdown code blocks
    16→    const cleanText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '');
    17→    const jsonMatch = cleanText.match(/\[[\s\S]*\]/);
    18→
    19→    if (!jsonMatch) {
    20→      logger.warn('No JSON array found in response');
    21→      return [];
    22→    }
    23→
    24→    const results: ParsedSearchResult[] = JSON.parse(jsonMatch[0]);
    25→    if (!Array.isArray(results)) {
    26→      return [];
    27→    }
    28→
    29→    // Build category to URL mapping
    30→    const categoryToUrl = buildCategoryUrlMap(manifest.files);
    31→
    32→    const mapped = results.map(r => mapToFileSearchResult(r, categoryToUrl));
    33→    return sortByRelevance(mapped);
    34→  } catch (error) {
    35→    logger.error({ error }, 'Failed to parse search results');
    36→    return [];
    37→  }
    38→}
    39→
    40→/**
    41→ * Sort results by relevance score (high > medium > low > undefined)
    42→ * Higher relevance results appear first for consistent context ordering
    43→ */
    44→function sortByRelevance(results: FileSearchResult[]): FileSearchResult[] {
    45→  const order: Record<string, number> = { high: 0, medium: 1, low: 2 };
    46→  return [...results].sort((a, b) => {
    47→    const aScore = a.relevance ? (order[a.relevance] ?? 3) : 3;
    48→    const bScore = b.relevance ? (order[b.relevance] ?? 3) : 3;
    49→    return aScore - bScore;
    50→  });
    51→}
    52→
    53→/**
    54→ * Build a map from category to URL
    55→ */
    56→function buildCategoryUrlMap(files: ManifestFile[]): Map<string, string> {
    57→  const categoryToUrl = new Map<string, string>();
    58→
    59→  files.forEach(file => {
    60→    if (file.category && file.url) {
    61→      categoryToUrl.set(file.category, file.url);
    62→    }
    63→  });
    64→
    65→  return categoryToUrl;
    66→}
    67→
    68→/**
    69→ * Map parsed result to FileSearchResult
    70→ */
    71→function mapToFileSearchResult(
    72→  result: ParsedSearchResult,
    73→  categoryToUrl: Map<string, string>
    74→): FileSearchResult {
    75→  const category = result.category || (result.source_type === 'web' ? 'トップページ' : 'Q&A');
    76→  const url = categoryToUrl.get(category) || 'https://wmg2027.jp/';
    77→
    78→  return {
    79→    text: result.answer || '',
    80→    original_question: result.original_question || result.question || '',
    81→    display_name: result.source_type === 'web' ? '公式サイト' : 'Q&Aデータ',
    82→    uri: url,
    83→    source_type: (result.source_type as 'qa' | 'web') || 'qa',
    84→    category: category,
    85→    locale: 'ja',
    86→    relevance: result.relevance as 'high' | 'medium' | 'low' | undefined,
    87→  };
    88→}
    89→
    90→/**
    91→ * Get fallback context when search fails or returns no results
    92→ */
    93→export function getFallbackContext(): FileSearchResult[] {
    94→  return [
    95→    {
    96→      text: 'この質問に関する具体的な情報は見つかりませんでした。ワールドマスターズゲームズ2027に関する詳細情報は、公式サイトをご確認ください。',
    97→      display_name: '公式サイト案内',
    98→      uri: 'https://wmg2027.jp/',
    99→      source_type: 'web',
   100→      locale: 'ja',
   101→    },
   102→  ];
   103→}
