     1→/**
     2→ * PII (Personal Identifiable Information) Validator
     3→ * 個人情報検証モジュール（API用）
     4→ *
     5→ * scripts/data-upload/lib/pii-detector.tsと同じロジックを使用
     6→ */
     7→
     8→/**
     9→ * Credit card number patterns
    10→ * - Visa: starts with 4, 13-16 digits
    11→ * - Mastercard: starts with 51-55, 16 digits
    12→ * - JCB: starts with 3528-3589, 16 digits
    13→ * - AMEX: starts with 34 or 37, 15 digits
    14→ * - Diners: starts with 36, 38, or 300-305, 14 digits
    15→ * Supports formats: plain, hyphenated, spaced
    16→ * Note: JCB pattern must come before Diners to avoid incorrect matching
    17→ */
    18→const CREDIT_CARD_PATTERN =
    19→  /(?:4[0-9]{12,15}|4[0-9]{3}[-\s]?[0-9]{4}[-\s]?[0-9]{4}[-\s]?[0-9]{1,4}|5[1-5][0-9]{14}|5[1-5][0-9]{2}[-\s]?[0-9]{4}[-\s]?[0-9]{4}[-\s]?[0-9]{4}|3[47][0-9]{13}|3[47][0-9]{2}[-\s]?[0-9]{6}[-\s]?[0-9]{5}|35(?:2[89]|[3-8][0-9])[0-9]{12}|35(?:2[89]|[3-8][0-9])[-\s]?[0-9]{4}[-\s]?[0-9]{4}[-\s]?[0-9]{4}|3(?:0[0-5]|[68][0-9])[0-9]{11,12})/g;
    20→
    21→/**
    22→ * My Number (マイナンバー) pattern
    23→ * 12-digit individual number, can be formatted with or without hyphens/spaces
    24→ */
    25→const MY_NUMBER_PATTERN = /(?<!\d)(?:\d{4}[-\s]?\d{4}[-\s]?\d{4}|\d{12})(?!\d)/g;
    26→
    27→/**
    28→ * International phone number patterns
    29→ * - E.164 format: +[country code][number] (e.g., +81-90-1234-5678)
    30→ * - Common formats with country codes
    31→ */
    32→const INTERNATIONAL_PHONE_PATTERN =
    33→  /\+[1-9]\d{0,2}[-\s.]?\(?\d{1,4}\)?[-\s.]?\d{1,4}[-\s.]?\d{1,9}/g;
    34→
    35→// Order matters: more specific patterns should come first
    36→const PII_PATTERNS = {
    37→  email: /[\w.-]+@[\w.-]+\.\w+/g,
    38→  internationalPhone: INTERNATIONAL_PHONE_PATTERN,
    39→  creditCard: CREDIT_CARD_PATTERN,
    40→  myNumber: MY_NUMBER_PATTERN,
    41→  phone: /\d{2,4}-\d{2,4}-\d{4}/g,
    42→  address:
    43→    /(東京都|大阪府|京都府|兵庫県|奈良県|滋賀県|和歌山県|北海道|青森県|岩手県|宮城県|秋田県|山形県|福島県|茨城県|栃木県|群馬県|埼玉県|千葉県|神奈川県|新潟県|富山県|石川県|福井県|山梨県|長野県|岐阜県|静岡県|愛知県|三重県|鳥取県|島根県|岡山県|広島県|山口県|徳島県|香川県|愛媛県|高知県|福岡県|佐賀県|長崎県|熊本県|大分県|宮崎県|鹿児島県|沖縄県).+(市|区|町|村)/g,
    44→};
    45→
    46→export type PIIType =
    47→  | 'email'
    48→  | 'phone'
    49→  | 'internationalPhone'
    50→  | 'creditCard'
    51→  | 'myNumber'
    52→  | 'address';
    53→
    54→export interface PIIDetectionResult {
    55→  found: boolean;
    56→  type?: PIIType;
    57→  matches?: string[];
    58→}
    59→
    60→/**
    61→ * Validate My Number using check digit algorithm
    62→ * マイナンバーのチェックデジットを検証
    63→ * @param number - 12-digit number string (digits only)
    64→ * @returns true if check digit is valid
    65→ */
    66→function validateMyNumberCheckDigit(number: string): boolean {
    67→  if (number.length !== 12) return false;
    68→
    69→  const digits = number.split('').map(d => parseInt(d, 10));
    70→  const checkDigit = digits[11];
    71→
    72→  // Calculate check digit using the official algorithm
    73→  // Weights for positions 1-11 are: 6,5,4,3,2,7,6,5,4,3,2
    74→  const weights = [6, 5, 4, 3, 2, 7, 6, 5, 4, 3, 2];
    75→  let sum = 0;
    76→
    77→  for (let i = 0; i < 11; i++) {
    78→    sum += digits[i] * weights[i];
    79→  }
    80→
    81→  const remainder = sum % 11;
    82→  const expectedCheckDigit = remainder <= 1 ? 0 : 11 - remainder;
    83→
    84→  return checkDigit === expectedCheckDigit;
    85→}
    86→
    87→/**
    88→ * Basic Luhn algorithm check for credit card numbers
    89→ * @param cardNumber - Credit card number (digits only)
    90→ * @returns true if passes Luhn check
    91→ */
    92→function validateLuhn(cardNumber: string): boolean {
    93→  const digits = cardNumber
    94→    .split('')
    95→    .reverse()
    96→    .map(d => parseInt(d, 10));
    97→  let sum = 0;
    98→
    99→  for (let i = 0; i < digits.length; i++) {
   100→    let digit = digits[i];
   101→    if (i % 2 === 1) {
   102→      digit *= 2;
   103→      if (digit > 9) digit -= 9;
   104→    }
   105→    sum += digit;
   106→  }
   107→
   108→  return sum % 10 === 0;
   109→}
   110→
   111→export function detectPII(text: string): PIIDetectionResult {
   112→  for (const [type, pattern] of Object.entries(PII_PATTERNS)) {
   113→    // Reset regex state
   114→    pattern.lastIndex = 0;
   115→    const matches = text.match(pattern);
   116→
   117→    if (matches && matches.length > 0) {
   118→      // Additional validation for specific types
   119→      if (type === 'myNumber') {
   120→        const validMatches = matches.filter(m => {
   121→          const digitsOnly = m.replace(/[-\s]/g, '');
   122→          return validateMyNumberCheckDigit(digitsOnly);
   123→        });
   124→        if (validMatches.length > 0) {
   125→          return {
   126→            found: true,
   127→            type: type as PIIType,
   128→            matches: validMatches,
   129→          };
   130→        }
   131→        continue;
   132→      }
   133→
   134→      if (type === 'creditCard') {
   135→        const validMatches = matches.filter(m => {
   136→          const digitsOnly = m.replace(/[-\s]/g, '');
   137→          return validateLuhn(digitsOnly);
   138→        });
   139→        if (validMatches.length > 0) {
   140→          return {
   141→            found: true,
   142→            type: type as PIIType,
   143→            matches: validMatches,
   144→          };
